{
  "schemaVersion": 2,
  "id": "reading-edge-pack",
  "name": "Reading Edge Pack",
  "version": "1.0.0",
  "entry": null,
  "pluginType": "ui-snippet",
  "capabilities": [
    "theme.snippet"
  ],
  "platforms": [
    "desktop",
    "web"
  ],
  "requiresRestart": false,
  "experimental": false,
  "minAppVersion": "0.6.0",
  "maxAppVersion": null,
  "permissions": {
    "theme": {
      "register": true
    }
  },
  "contributes": {
    "theme": {
      "style": [],
      "snippets": [
        {
          "file": "theme/snippets/reading-edge-pack.css",
          "id": "reading-edge-pack",
          "label": "Reading Edge Fade",
          "description": "Subtle top/bottom viewport fade while scrolling.",
          "defaultEnabled": true
        }
      ],
      "tokens": [],
      "defaultEnable": {
        "snippets": [
          "reading-edge-pack"
        ]
      }
    },
    "commands": [],
    "preferencesSections": [],
    "panels": []
  }
}

/**
 * Reading edge fade — UI snippet (subtle top / bottom)
 *
 * Soft vignette at the scroll viewport edges while the document scrolls underneath.
 * Overlays sit on `.tiptap-editor-shell` (fixed to the viewport, not the content).
 *
 * Copy to ~/.luna/theme/snippets/reading-edge-fade.css → Rescan → enable in UI snippets.
 * Enable only ONE reading-fade snippet at a time (they share the same overlay hooks).
 */

.preview-pane.markdown-visual-editor .tiptap-editor-shell {
  --reading-fade-size: 40px;
  --reading-fade-color: var(--surface-editor, var(--surface-panel));
}

.preview-pane.markdown-visual-editor .tiptap-editor-shell::before,
.preview-pane.markdown-visual-editor .tiptap-editor-shell::after {
  content: '';
  position: absolute;
  left: 0;
  right: 0;
  height: var(--reading-fade-size);
  pointer-events: none;
  z-index: 3;
}

.preview-pane.markdown-visual-editor .tiptap-editor-shell::before {
  top: 0;
  background: linear-gradient(
    to bottom,
    var(--reading-fade-color) 0%,
    transparent 100%
  );
}

.preview-pane.markdown-visual-editor .tiptap-editor-shell::after {
  bottom: 0;
  background: linear-gradient(
    to top,
    var(--reading-fade-color) 0%,
    transparent 100%
  );
}
